import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export class TradeResultParser implements IMessageParser
{
private _success = false;
private _message = '';

public flush(): boolean
{
this._success = false;
this._message = '';
return true;
}

public parse(wrapper: IMessageDataWrapper): boolean
{
if(!wrapper) return false;

// Must match TradeResultComposer.java
this._success = wrapper.readBoolean();
this._message = wrapper.readString();
return true;
}

public get success(): boolean { return this._success; }
public get message(): string { return this._message; }
}